  1→use agentrail_core::error::{Error, Result};
  2→use agentrail_core::{SagaStatus, StepStatus};
  3→use agentrail_store::{domain, saga, skill, step, trajectory};
  4→use std::path::Path;
  5→
  6→/// Returns exit code: 0 = active step found, 1 = saga complete, 2 = no saga
  7→pub fn run(saga_path: &Path) -> Result<u8> {
  8→    if !saga::saga_exists(saga_path) {
  9→        eprintln!("No saga found. Run `agentrail init` to create one.");
 10→        return Ok(2);
 11→    }
 12→
 13→    let config = saga::load_saga(saga_path)?;
 14→    if config.status == SagaStatus::Completed {
 15→        println!("Saga '{}' is complete. No more steps.", config.name);
 16→        return Ok(1);
 17→    }
 18→
 19→    let saga_dir = saga::saga_dir(saga_path);
 20→
 21→    // Print plan
 22→    let plan_path = saga_path.join(&config.plan_file);
 23→    if plan_path.is_file() {
 24→        let plan = std::fs::read_to_string(&plan_path)?;
 25→        println!("=== PLAN ===");
 26→        println!("{}", plan.trim());
 27→        println!();
 28→    }
 29→
 30→    // Print step list
 31→    let steps = step::list_steps(&saga_dir)?;
 32→    if !steps.is_empty() {
 33→        println!("=== STEPS ===");
 34→        for (_, s) in &steps {
 35→            let marker = match s.status {
 36→                StepStatus::Completed => "x",
 37→                StepStatus::InProgress => ">",
 38→                StepStatus::Blocked => "!",
 39→                StepStatus::Pending => " ",
 40→            };
 41→            let here = if s.number == config.current_step {
 42→                " <-- YOU ARE HERE"
 43→            } else {
 44→                ""
 45→            };
 46→            println!(
 47→                "  [{}] {:03}-{} [{}]: {}{}",
 48→                marker, s.number, s.slug, s.role, s.description, here
 49→            );
 50→        }
 51→        println!();
 52→    }
 53→
 54→    // Print current step details
 55→    if config.current_step > 0 {
 56→        match step::find_step_dir(&saga_dir, config.current_step) {
 57→            Ok(step_dir) => {
 58→                let step_config = step::load_step(&step_dir)?;
 59→                println!(
 60→                    "=== CURRENT STEP: {:03}-{} [{}] ===",
 61→                    step_config.number, step_config.slug, step_config.role
 62→                );
 63→                println!("Status: {}", step_config.status);
 64→                println!("Description: {}", step_config.description);
 65→
 66→                if let Some(ref task_type) = step_config.task_type {
 67→                    println!("Task type: {}", task_type);
 68→                }
 69→
 70→                if !step_config.context_files.is_empty() {
 71→                    println!("\nContext files:");
 72→                    for f in &step_config.context_files {
 73→                        println!("  - {}", f);
 74→                    }
 75→                }
 76→
 77→                let prompt_path = step_dir.join("prompt.md");
 78→                if prompt_path.is_file() {
 79→                    let prompt = std::fs::read_to_string(&prompt_path)?;
 80→                    if !prompt.trim().is_empty() {
 81→                        println!("\n=== PROMPT ===");
 82→                        println!("{}", prompt.trim());
 83→                    }
 84→                }
 85→
 86→                // XSkill dual memory: inject skill doc + past experiences
 87→                if let Some(ref task_type) = step_config.task_type {
 88→                    // Skill (strategic workflow) -- local first, then domain repo
 89→                    let local_skill = skill::load_skill(&saga_dir, task_type)?;
 90→                    let s = if local_skill.is_some() {
 91→                        local_skill
 92→                    } else if let Some((domain_dir, _)) =
 93→                        domain::find_domain_for_task(&saga_dir, task_type)?
 94→                    {
 95→                        skill::load_skill(&domain_dir, task_type)?
 96→                    } else {
 97→                        None
 98→                    };
 99→                    if let Some(s) = s {
100→                        println!("\n=== SKILL: {} (v{}) ===", task_type, s.version);
101→                        if !s.procedure.summary.is_empty() {
102→                            println!("{}", s.procedure.summary);
103→                        }
104→                        if !s.procedure.steps.is_empty() {
105→                            println!("\nProcedure:");
106→                            for (i, step_text) in s.procedure.steps.iter().enumerate() {
107→                                println!("  {}. {}", i + 1, step_text);
108→                            }
109→                        }
110→                        if !s.success_patterns.is_empty() {
111→                            println!("\nSuccess patterns:");
112→                            for p in &s.success_patterns {
113→                                println!("  - {}", p);
114→                            }
115→                        }
116→                        if !s.common_failures.is_empty() {
117→                            println!("\nKnown failure modes:");
118→                            for f in &s.common_failures {
119→                                println!("  - {} ({}x): {}", f.mode, f.frequency, f.description);
120→                            }
121→                        }
122→                    }
123→
124→                    // Experiences (tactical per-run records)
125→                    let successes = trajectory::retrieve_successes(&saga_dir, task_type, 3)?;
126→                    if !successes.is_empty() {
127→                        println!("\n=== PAST SUCCESSES ({}) ===", task_type);
128→                        for t in &successes {
129→                            println!(
130→                                "  [{}] action={}, result={}, reward={:+}",
131→                                t.timestamp, t.action, t.result, t.reward
132→                            );
133→                        }
134→                    }
135→                }
136→
137→                println!();
138→                println!("=== WHEN DONE ===");
139→                println!("Run: agentrail begin    (if not yet started)");
140→                println!(
141→                    "Run: agentrail complete --summary \"what you did\" --next-slug <slug> --next-prompt \"next instructions\""
142→                );
143→                println!(
144→                    "  Or: agentrail complete --summary \"what you did\" --done   (if this is the last step)"
145→                );
146→            }
147→            Err(Error::NoCurrentStep) => {
148→                println!(
149→                    "No step {} found. Use `agentrail complete` to create the next step.",
150→                    config.current_step
151→                );
152→            }
153→            Err(e) => return Err(e),
154→        }
155→    } else {
156→        println!("Saga initialized but no steps created yet.");
157→        println!(
158→            "Run: agentrail complete --summary \"initial setup\" --next-slug <slug> --next-prompt \"instructions\""
159→        );
160→    }
161→
162→    Ok(0)
163→}
