 1→/// Prelude tier determines which pre-compiled REPL binary to load.
 2→#[derive(Clone, Copy, PartialEq, Eq, Debug)]
 3→pub enum PreludeTier {
 4→    Bare,
 5→    Minimal,
 6→    Standard,
 7→    Full,
 8→    /// Scheme-flavored prelude: #t/#f, define-fn, let*, equal?, even?/odd?
 9→    Scheme,
10→}
11→
12→impl PreludeTier {
13→    pub fn label(self) -> &'static str {
14→        match self {
15→            Self::Bare => "Bare",
16→            Self::Minimal => "Minimal",
17→            Self::Standard => "Standard",
18→            Self::Full => "Full",
19→            Self::Scheme => "Scheme",
20→        }
21→    }
22→
23→    pub fn description(self) -> &'static str {
24→        match self {
25→            Self::Bare => "No prelude — raw primitives only",
26→            Self::Minimal => "6 comparison functions",
27→            Self::Standard => "~40 functions: list ops, macros, strings, I/O",
28→            Self::Full => "~65 functions: standard + lazy, threading, anaphora",
29→            Self::Scheme => "Scheme-flavored: #t/#f, define-fn, let*, equal?, even?/odd?",
30→        }
31→    }
32→
33→    pub fn assembly(self) -> &'static str {
34→        match self {
35→            Self::Bare => include_str!("../asm/repl-bare.s"),
36→            Self::Minimal => include_str!("../asm/repl-minimal.s"),
37→            Self::Standard => include_str!("../asm/repl-standard.s"),
38→            Self::Full => include_str!("../asm/repl-full.s"),
39→            Self::Scheme => include_str!("../asm/repl-scheme.s"),
40→        }
41→    }
42→
43→    pub const ALL: [PreludeTier; 5] = [
44→        Self::Bare,
45→        Self::Minimal,
46→        Self::Standard,
47→        Self::Full,
48→        Self::Scheme,
49→    ];
50→}
51→
52→/// Stack size configuration for the COR24 EBR region.
53→#[derive(Clone, Copy, PartialEq, Eq, Debug)]
54→pub enum StackSize {
55→    /// 3 KB — matches MachXO hardware default
56→    ThreeKb,
57→    /// 8 KB — full EBR window, needed for deep recursion
58→    EightKb,
59→}
60→
61→impl StackSize {
62→    pub fn initial_sp(self) -> u32 {
63→        match self {
64→            Self::ThreeKb => 0xFEEC00,
65→            Self::EightKb => 0xFF0000,
66→        }
67→    }
68→
69→    pub fn label(self) -> &'static str {
70→        match self {
71→            Self::ThreeKb => "3 KB",
72→            Self::EightKb => "8 KB",
73→        }
74→    }
75→
76→    pub fn bytes(self) -> u32 {
77→        match self {
78→            Self::ThreeKb => 3072,
79→            Self::EightKb => 8192,
80→        }
81→    }
82→
83→    pub const ALL: [StackSize; 2] = [Self::ThreeKb, Self::EightKb];
84→}
