 76→impl Repl {
 77→    fn load_binary(&mut self) {
 78→        let asm_source = self.prelude.assembly();
 79→        let mut asm = Assembler::new();
 80→        let result = asm.assemble(asm_source);
 81→
 82→        if !result.errors.is_empty() {
 83→            self.status = format!("Assembly failed: {}", result.errors[0]);
 84→            self.loaded = false;
 85→            return;
 86→        }
 87→
 88→        self.emulator.hard_reset();
 89→        self.emulator.set_uart_tx_busy_cycles(0); // instant TX in browser
 90→        for (addr, &byte) in result.bytes.iter().enumerate() {
 91→            self.emulator.write_byte(addr as u32, byte);
 92→        }
 93→        self.emulator.set_pc(0);
 94→        self.emulator.set_reg(4, self.stack_size.initial_sp());
 95→
 96→        // Capture memory pool addresses from symbol table
 97→        self.addr_heap_next = result.labels.get("_heap_next").copied();
 98→        self.addr_sym_count = result.labels.get("_sym_count").copied();
 99→        self.addr_str_pool_next = result.labels.get("_str_pool_next").copied();
100→
101→        self.output.clear();
102→        self.transcript.clear();
103→        self.uart_seen = 0;
104→        self.uart_tx_queue.clear();
105→        self.loaded = true;
106→        self.waiting_for_input = false;
107→        self.led_on = false;
108→        self.switch_pressed = false;
109→        self.heap_used = 0;
110→        self.sym_used = 0;
111→        self.str_pool_used = 0;
112→        self.stack_depth = 0;
113→        self.cpu_load = 0.0;
114→        self.status = format!(
115→            "Loaded {} bytes ({}, {} stack).",
116→            result.bytes.len(),
117→            self.prelude.label(),
118→            self.stack_size.label(),
119→        );
120→
121→        self.emulator.resume();
122→        self.running = true;
123→    }
124→
125→    fn view_gauge(&self, label: &str, used: u32, total: u32) -> Html {
126→        let pct = if total > 0 { (used as f64 / total as f64 * 100.0).min(100.0) } else { 0.0 };
127→        let color_class = if pct < 60.0 { "gauge-green" }
128→            else if pct < 85.0 { "gauge-yellow" }
129→            else { "gauge-red" };
130→        html! {
131→            <div class="gauge-row">
132→                <span class="gauge-label">{ label }</span>
133→                <div class="gauge-track">
134→                    <div class={classes!("gauge-fill", color_class)}
135→                         style={format!("width:{}%", pct)} />
136→                </div>
137→                <span class="gauge-text">{ format!("{}/{}", used, total) }</span>
138→            </div>
139→        }
140→    }
141→
142→    fn view_cpu_gauge(&self) -> Html {
143→        let pct = (self.cpu_load * 100.0).min(100.0);
144→        let color_class = if pct < 20.0 { "gauge-green" }
145→            else if pct < 60.0 { "gauge-yellow" }
146→            else { "gauge-red" };
147→        let label = if pct < 1.0 { "idle" }
148→            else if pct > 90.0 { "pegged" }
149→            else { "running" };
150→        html! {
151→            <div class="gauge-row">
152→                <span class="gauge-label">{ "CPU" }</span>
153→                <div class="gauge-track">
154→                    <div class={classes!("gauge-fill", color_class)}
155→                         style={format!("width:{}%", pct)} />
156→                </div>
157→                <span class="gauge-text">{ label }</span>
158→            </div>
159→        }
160→    }
161→
162→    fn send_input(&mut self) {
163→        for line in self.input.lines() {
164→            if line.trim().is_empty() {
165→                continue;
166→            }
167→            for byte in line.bytes() {
168→                self.uart_tx_queue.push_back(byte);
169→            }
170→            self.uart_tx_queue.push_back(b'\n');
171→        }
172→    }
173→}
