  1→use agentrail_core::error::{Error, Result};
  2→use agentrail_core::{StepConfig, StepRole, StepStatus};
  3→use std::path::{Path, PathBuf};
  4→
  5→/// Format step directory name: NNN-slug
  6→fn step_dir_name(number: u32, slug: &str) -> String {
  7→    format!("{:03}-{}", number, slug)
  8→}
  9→
 10→/// Get the step directory path within the saga dir.
 11→pub fn step_dir(saga_dir: &Path, number: u32, slug: &str) -> PathBuf {
 12→    saga_dir.join("steps").join(step_dir_name(number, slug))
 13→}
 14→
 15→/// Find a step directory by number (slug may vary).
 16→pub fn find_step_dir(saga_dir: &Path, number: u32) -> Result<PathBuf> {
 17→    let steps_dir = saga_dir.join("steps");
 18→    if !steps_dir.is_dir() {
 19→        return Err(Error::NoSteps);
 20→    }
 21→    let prefix = format!("{:03}-", number);
 22→    for entry in std::fs::read_dir(&steps_dir)? {
 23→        let entry = entry?;
 24→        if let Some(name) = entry.file_name().to_str()
 25→            && name.starts_with(&prefix)
 26→        {
 27→            return Ok(entry.path());
 28→        }
 29→    }
 30→    Err(Error::NoCurrentStep)
 31→}
 32→
 33→pub fn load_step(step_dir: &Path) -> Result<StepConfig> {
 34→    let file = step_dir.join("step.toml");
 35→    let content = std::fs::read_to_string(&file)?;
 36→    Ok(toml::from_str(&content)?)
 37→}
 38→
 39→pub fn save_step(step_dir: &Path, config: &StepConfig) -> Result<()> {
 40→    let file = step_dir.join("step.toml");
 41→    let content = toml::to_string_pretty(config)?;
 42→    std::fs::write(&file, content)?;
 43→    Ok(())
 44→}
 45→
 46→pub struct CreateStepParams<'a> {
 47→    pub saga_dir: &'a Path,
 48→    pub number: u32,
 49→    pub slug: &'a str,
 50→    pub prompt: &'a str,
 51→    pub description: &'a str,
 52→    pub role: StepRole,
 53→    pub context_files: &'a [String],
 54→    pub task_type: Option<&'a str>,
 55→    pub job_spec: Option<agentrail_core::JobSpec>,
 56→}
 57→
 58→pub fn create_step(p: &CreateStepParams<'_>) -> Result<PathBuf> {
 59→    let saga_dir = p.saga_dir;
 60→    let number = p.number;
 61→    let slug = p.slug;
 62→    let prompt = p.prompt;
 63→    let description = p.description;
 64→    let role = p.role.clone();
 65→    let context_files = p.context_files;
 66→    let task_type = p.task_type;
 67→    let dir = step_dir(saga_dir, number, slug);
 68→    std::fs::create_dir_all(&dir)?;
 69→
 70→    let config = StepConfig {
 71→        number,
 72→        slug: slug.to_string(),
 73→        status: StepStatus::Pending,
 74→        description: description.to_string(),
 75→        role,
 76→        context_files: context_files.to_vec(),
 77→        created_at: agentrail_core::timestamp_iso(),
 78→        completed_at: None,
 79→        transcript_file: None,
 80→        job_spec: p.job_spec.clone(),
 81→        packet_file: None,
 82→        task_type: task_type.map(|s| s.to_string()),
 83→    };
 84→
 85→    save_step(&dir, &config)?;
 86→    std::fs::write(dir.join("prompt.md"), prompt)?;
 87→
 88→    Ok(dir)
 89→}
 90→
 91→pub fn transition_step(config: &mut StepConfig, to: StepStatus) -> Result<()> {
 92→    let valid = matches!(
 93→        (&config.status, &to),
 94→        (StepStatus::Pending, StepStatus::InProgress)
 95→            | (StepStatus::InProgress, StepStatus::Completed)
 96→            | (StepStatus::InProgress, StepStatus::Blocked)
 97→    );
 98→
 99→    if !valid {
100→        return Err(Error::InvalidStepTransition {
101→            from: config.status.to_string(),
102→            to: to.to_string(),
103→        });
104→    }
105→
106→    if to == StepStatus::Completed {
107→        config.completed_at = Some(agentrail_core::timestamp_iso());
108→    }
109→
110→    config.status = to;
111→    Ok(())
112→}
113→
114→/// List all steps sorted by number.
115→pub fn list_steps(saga_dir: &Path) -> Result<Vec<(PathBuf, StepConfig)>> {
116→    let steps_dir = saga_dir.join("steps");
117→    if !steps_dir.is_dir() {
118→        return Ok(vec![]);
119→    }
120→
121→    let mut steps = Vec::new();
122→    for entry in std::fs::read_dir(&steps_dir)? {
123→        let entry = entry?;
124→        if entry.file_type()?.is_dir() {
125→            let step_toml = entry.path().join("step.toml");
126→            if step_toml.is_file() {
127→                let config = load_step(&entry.path())?;
128→                steps.push((entry.path(), config));
129→            }
130→        }
131→    }
132→
133→    steps.sort_by_key(|(_, c)| c.number);
134→    Ok(steps)
135→}
136→
137→/// Save summary to a step directory.
138→pub fn save_summary(step_dir: &Path, content: &str) -> Result<()> {
139→    std::fs::write(step_dir.join("summary.md"), content)?;
140→    Ok(())
141→}
