430→    // ===== Disassembly =====
431→
432→    /// Disassemble one instruction at the given address.
433→    /// Returns (mnemonic_string, instruction_size_in_bytes).
434→    pub fn disassemble_at(&self, addr: u32) -> (String, u32) {
435→        use crate::cpu::instruction::{reg_name, InstructionFormat};
436→
437→        let inst_byte = self.cpu.read_byte(addr);
438→        let decoded = self.decode_rom.decode(inst_byte);
439→        if decoded == 0xFFF {
440→            return (format!(".byte 0x{:02X}", inst_byte), 1);
441→        }
442→
443→        let inst = DecodedInstruction::from_decoded(decoded);
444→        let format = inst.opcode.format();
445→        let size = match format {
446→            InstructionFormat::SingleByte => 1,
447→            InstructionFormat::TwoBytes => 2,
448→            InstructionFormat::FourBytes => 4,
449→        };
450→
451→        let text = match format {
452→            InstructionFormat::SingleByte => match inst.opcode {
453→                Opcode::Pop => format!("pop  {}", reg_name(inst.ra)),
454→                Opcode::Push => format!("push {}", reg_name(inst.ra)),
455→                Opcode::Jmp => format!("jmp  ({})", reg_name(inst.ra)),
456→                Opcode::Jal => {
457→                    format!("jal  {},({})", reg_name(inst.ra), reg_name(inst.rb))
458→                }
459→                Opcode::Mov if inst.rb == 5 => {
460→                    format!("mov  {},c", reg_name(inst.ra))
461→                }
462→                _ => {
463→                    format!(
464→                        "{:4} {},{}",
465→                        inst.opcode.mnemonic(),
466→                        reg_name(inst.ra),
467→                        reg_name(inst.rb)
468→                    )
469→                }
470→            },
471→            InstructionFormat::TwoBytes => {
472→                let imm = self.cpu.read_byte(addr + 1);
473→                let signed = imm as i8;
474→                match inst.opcode {
475→                    Opcode::Bra | Opcode::Brf | Opcode::Brt => {
476→                        let branch_base = addr.wrapping_add(4);
477→                        let target =
478→                            CpuState::mask_24(branch_base.wrapping_add(CpuState::sign_extend_8(imm)));
479→                        format!(
480→                            "{:4} 0x{:06X}",
481→                            inst.opcode.mnemonic(),
482→                            target
483→                        )
484→                    }
485→                    Opcode::Lc | Opcode::Lcu | Opcode::AddImm => {
486→                        format!(
487→                            "{:4} {},{}",
488→                            inst.opcode.mnemonic(),
489→                            reg_name(inst.ra),
490→                            signed
491→                        )
492→                    }
493→                    _ => {
494→                        // Lb, Lbu, Lw, Sb, Sw with offset
495→                        if signed == 0 {
496→                            format!(
497→                                "{:4} {},({})",
498→                                inst.opcode.mnemonic(),
499→                                reg_name(inst.ra),
500→                                reg_name(inst.rb)
501→                            )
502→                        } else {
503→                            format!(
504→                                "{:4} {},{}({})",
505→                                inst.opcode.mnemonic(),
506→                                reg_name(inst.ra),
507→                                signed,
508→                                reg_name(inst.rb)
509→                            )
510→                        }
511→                    }
512→                }
513→            }
514→            InstructionFormat::FourBytes => {
515→                let b0 = self.cpu.read_byte(addr + 1) as u32;
516→                let b1 = self.cpu.read_byte(addr + 2) as u32;
517→                let b2 = self.cpu.read_byte(addr + 3) as u32;
518→                let imm24 = b0 | (b1 << 8) | (b2 << 16);
519→                format!(
520→                    "{:4} {},0x{:06X}",
521→                    inst.opcode.mnemonic(),
522→                    reg_name(inst.ra),
523→                    imm24
524→                )
525→            }
526→        };
527→
528→        (text, size)
529→    }
530→
531→    /// Disassemble N instructions starting at addr
532→    pub fn disassemble(&self, addr: u32, count: usize) -> Vec<(u32, String, u32)> {
533→        let mut result = Vec::with_capacity(count);
534→        let mut pc = addr;
535→        for _ in 0..count {
536→            let (text, size) = self.disassemble_at(pc);
537→            result.push((pc, text, size));
538→            pc = CpuState::mask_24(pc + size);
539→        }
540→        result
541→    }
542→}
