  1→use agentrail_core::error::Result;
  2→use agentrail_core::{FailureMode, OutputContract, Procedure, Skill};
  3→use agentrail_store::{saga, skill, trajectory};
  4→use std::collections::HashMap;
  5→use std::path::Path;
  6→
  7→/// Distill trajectories for a task type into a skill document.
  8→/// Implements the XSkill accumulation phase.
  9→pub fn run(saga_path: &Path, task_type: &str) -> Result<()> {
 10→    let saga_dir = saga::saga_dir(saga_path);
 11→    let task_dir = saga_dir.join("trajectories").join(task_type);
 12→
 13→    if !task_dir.is_dir() {
 14→        println!("No trajectories found for task type '{task_type}'.");
 15→        return Ok(());
 16→    }
 17→
 18→    let all = trajectory::load_all_trajectories(&task_dir)?;
 19→    if all.is_empty() {
 20→        println!("No trajectories found for task type '{task_type}'.");
 21→        return Ok(());
 22→    }
 23→
 24→    let successes: Vec<_> = all.iter().filter(|t| t.reward > 0).collect();
 25→    let failures: Vec<_> = all.iter().filter(|t| t.reward < 0).collect();
 26→
 27→    println!(
 28→        "Distilling '{}': {} trajectories ({} successes, {} failures)",
 29→        task_type,
 30→        all.len(),
 31→        successes.len(),
 32→        failures.len()
 33→    );
 34→
 35→    // Extract common action patterns from successes
 36→    let mut action_counts: HashMap<&str, u32> = HashMap::new();
 37→    for t in &successes {
 38→        *action_counts.entry(t.action.as_str()).or_default() += 1;
 39→    }
 40→    let mut sorted_actions: Vec<_> = action_counts.into_iter().collect();
 41→    sorted_actions.sort_by(|a, b| b.1.cmp(&a.1));
 42→
 43→    // Build procedure from most common successful actions
 44→    let procedure_steps: Vec<String> = sorted_actions
 45→        .iter()
 46→        .take(5)
 47→        .map(|(action, count)| format!("{} (seen in {} successful runs)", action, count))
 48→        .collect();
 49→
 50→    // Extract success patterns (unique successful actions)
 51→    let success_patterns: Vec<String> = sorted_actions
 52→        .iter()
 53→        .filter(|(_, count)| *count > 1)
 54→        .map(|(action, _)| action.to_string())
 55→        .collect();
 56→
 57→    // Extract failure modes
 58→    let mut failure_counts: HashMap<&str, u32> = HashMap::new();
 59→    for t in &failures {
 60→        let mode = t
 61→            .result
 62→            .strip_prefix("failure: ")
 63→            .unwrap_or(t.result.as_str());
 64→        *failure_counts.entry(mode).or_default() += 1;
 65→    }
 66→    let common_failures: Vec<FailureMode> = failure_counts
 67→        .into_iter()
 68→        .map(|(mode, freq)| FailureMode {
 69→            mode: mode.to_string(),
 70→            description: format!("Observed in {} failed runs", freq),
 71→            frequency: freq,
 72→        })
 73→        .collect();
 74→
 75→    // Load existing skill or create new
 76→    let mut s = skill::load_skill(&saga_dir, task_type)?.unwrap_or_else(|| Skill {
 77→        task_type: task_type.to_string(),
 78→        version: 0,
 79→        updated_at: String::new(),
 80→        distilled_from: 0,
 81→        procedure: Procedure::default(),
 82→        success_patterns: vec![],
 83→        common_failures: vec![],
 84→        output_contract: OutputContract::default(),
 85→    });
 86→
 87→    // Update skill
 88→    s.version += 1;
 89→    s.updated_at = agentrail_core::timestamp_iso();
 90→    s.distilled_from = all.len() as u32;
 91→
 92→    if !procedure_steps.is_empty() {
 93→        s.procedure.steps = procedure_steps;
 94→    }
 95→    if s.procedure.summary.is_empty() {
 96→        s.procedure.summary = format!("Distilled from {} trajectories", all.len());
 97→    }
 98→    if !success_patterns.is_empty() {
 99→        s.success_patterns = success_patterns;
100→    }
101→    if !common_failures.is_empty() {
102→        s.common_failures = common_failures;
103→    }
104→
105→    let path = skill::save_skill(&saga_dir, &s)?;
106→    println!(
107→        "Saved skill v{} to {} ({} procedure steps, {} failure modes)",
108→        s.version,
109→        path.display(),
110→        s.procedure.steps.len(),
111→        s.common_failures.len()
112→    );
113→
114→    Ok(())
115→}
