  1→use agentrail_core::error::{Error, Result};
  2→use agentrail_core::{SagaStatus, StepRole, StepStatus, Trajectory};
  3→use agentrail_store::{domain, saga, step, trajectory};
  4→use std::path::Path;
  5→
  6→/// Run the orchestrator loop: auto-execute deterministic steps,
  7→/// pause at production/meta steps for agent intervention.
  8→/// Returns exit code: 0 = paused at agent step, 1 = saga complete, 2 = no work
  9→pub fn run(saga_path: &Path) -> Result<u8> {
 10→    let mut config = saga::load_saga(saga_path)?;
 11→    let saga_dir = saga::saga_dir(saga_path);
 12→
 13→    if config.status == SagaStatus::Completed {
 14→        println!("Saga '{}' is complete.", config.name);
 15→        return Ok(1);
 16→    }
 17→
 18→    if config.current_step == 0 {
 19→        println!("No steps to run. Use `agentrail complete` to create the first step.");
 20→        return Ok(2);
 21→    }
 22→
 23→    loop {
 24→        let step_dir = match step::find_step_dir(&saga_dir, config.current_step) {
 25→            Ok(d) => d,
 26→            Err(Error::NoCurrentStep) => {
 27→                println!("No more steps. Saga may be complete.");
 28→                return Ok(1);
 29→            }
 30→            Err(e) => return Err(e),
 31→        };
 32→
 33→        let mut step_config = step::load_step(&step_dir)?;
 34→
 35→        // Skip already completed steps
 36→        if step_config.status == StepStatus::Completed {
 37→            println!(
 38→                "  [skip] {:03}-{} already completed",
 39→                step_config.number, step_config.slug
 40→            );
 41→            // Try next step
 42→            config.current_step += 1;
 43→            saga::save_saga(saga_path, &config)?;
 44→            continue;
 45→        }
 46→
 47→        match step_config.role {
 48→            StepRole::Deterministic => {
 49→                println!(
 50→                    "  [exec] {:03}-{} [deterministic]",
 51→                    step_config.number, step_config.slug
 52→                );
 53→
 54→                // Transition to in-progress
 55→                if step_config.status == StepStatus::Pending {
 56→                    step::transition_step(&mut step_config, StepStatus::InProgress)?;
 57→                    step::save_step(&step_dir, &step_config)?;
 58→                }
 59→
 60→                // Execute the job
 61→                let result = execute_deterministic_step(&saga_dir, &step_config);
 62→
 63→                match result {
 64→                    Ok(summary) => {
 65→                        // Record success trajectory
 66→                        if let Some(ref task_type) = step_config.task_type {
 67→                            let t = Trajectory {
 68→                                task_type: task_type.clone(),
 69→                                state: serde_json::json!({"step": step_config.slug}),
 70→                                action: summary.clone(),
 71→                                result: "success".to_string(),
 72→                                reward: 1,
 73→                                timestamp: agentrail_core::timestamp_iso(),
 74→                            };
 75→                            trajectory::save_trajectory(&saga_dir, &t)?;
 76→                        }
 77→
 78→                        step::transition_step(&mut step_config, StepStatus::Completed)?;
 79→                        step::save_step(&step_dir, &step_config)?;
 80→                        step::save_summary(&step_dir, &summary)?;
 81→
 82→                        println!(
 83→                            "    -> completed: {}",
 84→                            agentrail_core::truncate(&summary, 60)
 85→                        );
 86→                    }
 87→                    Err(e) => {
 88→                        // Record failure trajectory
 89→                        if let Some(ref task_type) = step_config.task_type {
 90→                            let t = Trajectory {
 91→                                task_type: task_type.clone(),
 92→                                state: serde_json::json!({"step": step_config.slug}),
 93→                                action: "executor failed".to_string(),
 94→                                result: e.to_string(),
 95→                                reward: -1,
 96→                                timestamp: agentrail_core::timestamp_iso(),
 97→                            };
 98→                            trajectory::save_trajectory(&saga_dir, &t)?;
 99→                        }
100→
101→                        step::transition_step(&mut step_config, StepStatus::Blocked)?;
102→                        step::save_step(&step_dir, &step_config)?;
103→                        step::save_summary(&step_dir, &format!("BLOCKED: {e}"))?;
104→
105→                        println!("    -> FAILED: {e}");
106→                        println!("    Pausing loop. Fix the issue and re-run.");
107→                        return Ok(0);
108→                    }
109→                }
110→
111→                // Check if there's a next step
112→                let next_num = config.current_step + 1;
113→                if step::find_step_dir(&saga_dir, next_num).is_ok() {
114→                    config.current_step = next_num;
115→                    saga::save_saga(saga_path, &config)?;
116→                } else {
117→                    println!("  No more steps after {:03}.", step_config.number);
118→                    return Ok(1);
119→                }
120→            }
121→
122→            StepRole::Validation => {
123→                println!(
124→                    "  [validate] {:03}-{} [validation]",
125→                    step_config.number, step_config.slug
126→                );
127→
128→                if step_config.status == StepStatus::Pending {
129→                    step::transition_step(&mut step_config, StepStatus::InProgress)?;
130→                    step::save_step(&step_dir, &step_config)?;
131→                }
132→
133→                let result = run_validation_step(&saga_dir, &step_config);
134→
135→                match result {
136→                    Ok(summary) => {
137→                        step::transition_step(&mut step_config, StepStatus::Completed)?;
138→                        step::save_step(&step_dir, &step_config)?;
139→                        step::save_summary(&step_dir, &summary)?;
140→                        println!("    -> passed: {}", agentrail_core::truncate(&summary, 60));
141→                    }
142→                    Err(e) => {
143→                        step::transition_step(&mut step_config, StepStatus::Blocked)?;
144→                        step::save_step(&step_dir, &step_config)?;
145→                        step::save_summary(&step_dir, &format!("VALIDATION FAILED: {e}"))?;
146→                        println!("    -> FAILED: {e}");
147→                        return Ok(0);
148→                    }
149→                }
150→
151→                let next_num = config.current_step + 1;
152→                if step::find_step_dir(&saga_dir, next_num).is_ok() {
153→                    config.current_step = next_num;
154→                    saga::save_saga(saga_path, &config)?;
155→                } else {
156→                    println!("  No more steps after {:03}.", step_config.number);
157→                    return Ok(1);
158→                }
159→            }
160→
161→            // Production, Meta, Legacy: pause for agent
162→            _ => {
163→                println!(
164→                    "  [pause] {:03}-{} [{}] -- requires agent",
165→                    step_config.number, step_config.slug, step_config.role
166→                );
167→                println!("  Run `agentrail next` for full context.");
168→                return Ok(0);
169→            }
170→        }
171→    }
172→}
173→
174→fn execute_deterministic_step(
175→    saga_dir: &Path,
176→    step_config: &agentrail_core::StepConfig,
177→) -> Result<String> {
178→    let job = step_config
179→        .job_spec
180→        .as_ref()
181→        .ok_or_else(|| Error::JobFailed("Deterministic step has no job_spec".to_string()))?;
182→
183→    // Find domain that provides the executor
184→    if let Some((domain_dir, _)) =
185→        domain::find_domain_for_task(saga_dir, step_config.task_type.as_deref().unwrap_or(""))?
186→    {
187→        let result = agentrail_exec::run_shell_executor(&domain_dir, job)?;
188→        if result.success {
189→            Ok(format!(
190→                "Executed {} via {}: {}",
191→                job.kind,
192→                domain_dir.display(),
193→                result.outputs
194→            ))
195→        } else {
196→            Err(Error::JobFailed(
197→                result
198→                    .error
199→                    .unwrap_or_else(|| "executor returned failure".to_string()),
200→            ))
201→        }
202→    } else {
203→        Err(Error::JobFailed(format!(
204→            "No domain found for task type '{}'",
205→            step_config.task_type.as_deref().unwrap_or("(none)")
206→        )))
207→    }
208→}
209→
210→fn run_validation_step(
211→    saga_dir: &Path,
212→    step_config: &agentrail_core::StepConfig,
213→) -> Result<String> {
214→    let task_type = step_config.task_type.as_deref().unwrap_or("");
215→
216→    let (domain_dir, tt) = domain::find_domain_for_task(saga_dir, task_type)?.ok_or_else(|| {
217→        Error::ValidationFailed(format!("No domain found for task type '{task_type}'"))
218→    })?;
219→
220→    if tt.validators.is_empty() {
221→        return Ok("No validators configured".to_string());
222→    }
223→
224→    // Build context from job spec params or empty
225→    let context = step_config
226→        .job_spec
227→        .as_ref()
228→        .map(|j| j.params.clone())
229→        .unwrap_or(serde_json::json!({}));
230→
231→    let mut results = Vec::new();
232→    for check in &tt.validators {
233→        let vr = agentrail_validate::run_shell_validator(&domain_dir, check, &context)?;
234→        if !vr.valid {
235→            return Err(Error::ValidationFailed(format!(
236→                "Check '{}' failed: {}",
237→                check,
238→                vr.error.unwrap_or_else(|| "unknown".to_string())
239→            )));
240→        }
241→        results.push(format!("{check}: ok"));
242→    }
243→
244→    Ok(format!("All checks passed: {}", results.join(", ")))
245→}
