 1→//! Trajectory storage and retrieval for ICRL.
 2→//!
 3→//! Trajectories are stored as individual JSON files under:
 4→//!   .agentrail/trajectories/{task_type}/run_NNN.json
 5→
 6→use agentrail_core::Trajectory;
 7→use agentrail_core::error::Result;
 8→use std::path::{Path, PathBuf};
 9→
10→/// Save a trajectory record.
11→pub fn save_trajectory(saga_dir: &Path, trajectory: &Trajectory) -> Result<PathBuf> {
12→    let task_dir = saga_dir.join("trajectories").join(&trajectory.task_type);
13→    std::fs::create_dir_all(&task_dir)?;
14→
15→    let next_num = next_run_number(&task_dir)?;
16→    let filename = format!("run_{:03}.json", next_num);
17→    let path = task_dir.join(&filename);
18→
19→    let content = serde_json::to_string_pretty(trajectory)?;
20→    std::fs::write(&path, content)?;
21→
22→    Ok(path)
23→}
24→
25→/// Retrieve the N most recent successful trajectories for a task type.
26→pub fn retrieve_successes(
27→    saga_dir: &Path,
28→    task_type: &str,
29→    limit: usize,
30→) -> Result<Vec<Trajectory>> {
31→    let task_dir = saga_dir.join("trajectories").join(task_type);
32→    if !task_dir.is_dir() {
33→        return Ok(vec![]);
34→    }
35→
36→    let mut trajectories = load_all_trajectories(&task_dir)?;
37→    // Keep only successes (reward > 0), most recent first
38→    trajectories.retain(|t| t.reward > 0);
39→    trajectories.reverse();
40→    trajectories.truncate(limit);
41→    Ok(trajectories)
42→}
43→
44→/// Retrieve all trajectories for a task type.
45→pub fn load_all_trajectories(task_dir: &Path) -> Result<Vec<Trajectory>> {
46→    let mut entries: Vec<PathBuf> = std::fs::read_dir(task_dir)?
47→        .filter_map(|e| e.ok())
48→        .filter(|e| e.path().extension().is_some_and(|ext| ext == "json"))
49→        .map(|e| e.path())
50→        .collect();
51→
52→    entries.sort();
53→
54→    let mut trajectories = Vec::new();
55→    for path in entries {
56→        let content = std::fs::read_to_string(&path)?;
57→        let t: Trajectory = serde_json::from_str(&content)?;
58→        trajectories.push(t);
59→    }
60→
61→    Ok(trajectories)
62→}
63→
64→fn next_run_number(task_dir: &Path) -> Result<u32> {
65→    let mut max = 0u32;
66→    if task_dir.is_dir() {
67→        for entry in std::fs::read_dir(task_dir)? {
68→            let entry = entry?;
69→            if let Some(name) = entry.file_name().to_str()
70→                && let Some(num_str) = name
71→                    .strip_prefix("run_")
72→                    .and_then(|s| s.strip_suffix(".json"))
73→                && let Ok(n) = num_str.parse::<u32>()
74→            {
75→                max = max.max(n);
76→            }
77→        }
78→    }
79→    Ok(max + 1)
80→}
