36→        return Err(Error::SagaAlreadyExists {
37→            path: path.to_path_buf(),
38→        });
39→    }
40→
41→    std::fs::create_dir_all(dir.join("steps"))?;
42→    std::fs::create_dir_all(dir.join("trajectories"))?;
43→    std::fs::create_dir_all(dir.join("sessions"))?;
44→
45→    let plan_file = format!("{DIR_NAME}/plan.md");
46→    let config = SagaConfig {
47→        name: name.to_string(),
48→        status: SagaStatus::Active,
