138→            | crate::emulator::StopReason::Halted
139→            | crate::emulator::StopReason::Paused
140→            | crate::emulator::StopReason::Breakpoint(_) => Ok(()),
141→            crate::emulator::StopReason::InvalidInstruction(byte) => Err(JsValue::from_str(
